package com.hospital.management.controller.appointment;import com.hospital.management.model.*;import com.hospital.management.util.RequestUtil;import javax.servlet.http.*;import java.time.LocalDate;
final class AppointmentRequest {private AppointmentRequest(){}static AuthenticatedUser user(HttpServletRequest q){HttpSession s=q==null?null:q.getSession(false);Object u=s==null?null:s.getAttribute("authenticatedUser");return u instanceof AuthenticatedUser a?a:null;}static Long id(String v){try{long x=Long.parseLong(v);return x>0?x:null;}catch(Exception e){return null;}}static int number(String v,int d){try{return Integer.parseInt(v);}catch(Exception e){return d;}}static LocalDate date(String v){try{return v==null||v.isBlank()?null:LocalDate.parse(v);}catch(Exception e){return null;}}static AppointmentForm form(HttpServletRequest q){AppointmentForm f=new AppointmentForm();f.setAppointmentId(id(q.getParameter("appointmentId")));f.setPatientId(id(q.getParameter("patientId")));f.setDoctorId(id(q.getParameter("doctorId")));f.setAppointmentDate(q.getParameter("appointmentDate"));f.setStartTime(q.getParameter("startTime"));f.setReason(q.getParameter("reason"));f.setNotes(q.getParameter("notes"));f.setStatus(q.getParameter("status"));return f;}static AuditContext audit(HttpServletRequest q){return RequestUtil.buildAuditContext(q);}}
